async (params, browser) => {
  // Open newsletter homepage
  await browser.open(`https://${params.newsletter_slug}.substack.com`)

  // Wait for newsletter page to load
  await browser.waitForSelector('h1, [class*=\'publication\'], [class*=\'hero\'], [class*=\'navbar-title\']', 15000)

  // Let page fully render
  await browser.wait(2000)

  // Scroll to load posts
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(1500)

  // Scroll further
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(1500)

  // Extract newsletter details
